 1	import { Label, Tooltip, TooltipPosition } from '@patternfly/react-core';
 2	import { KialiIcon } from 'config/KialiIcon';
 3	import * as React from 'react';
 4	import { kialiStyle } from 'styles/StyleUtils';
 5	import { useKialiTranslation } from 'utils/I18nUtils';
 6	
 7	type Props = {
 8	  version?: string;
 9	};
10	
11	const lockIconStyle = kialiStyle({ marginLeft: '0.25rem' });
12	
13	const LockIcon = (): React.ReactElement => {
14	  return <KialiIcon.MtlsLock className={lockIconStyle} />;
15	};
16	
17	const TLSInfoComponent: React.FC<Props> = (props: Props) => {
18	  const { t } = useKialiTranslation();
19	
20	  return (
21	    <div style={{ textAlign: 'left' }}>
22	      <div>
23	        <div style={{ display: 'inline-block', width: '125px', whiteSpace: 'nowrap' }}>{t('Min TLS version')}</div>
24	        <Tooltip
25	          position={TooltipPosition.right}
26	          content={
27	            <div style={{ textAlign: 'left' }}>
28	              {t(
29	                `The minimum TLS version for connections among Istio workloads. Defaults to TLSV1_2 if not set. Set by the 'meshConfig.meshMTLS.minProtocolVersion' field.`
30	              )}
31	            </div>
32	          }
33	        >
34	          <Label isCompact color="blue" data-test={'label-TLS'}>
35	            <div style={{ display: '-webkit-box' }}>
36	              {props.version} <LockIcon></LockIcon>
37	            </div>
38	          </Label>
39	        </Tooltip>
40	      </div>
41	    </div>
42	  );
43	};
44	
45	export const TLSInfo = TLSInfoComponent;

